function Logger({ value }) {
  const historyRef = useRef([]);

  historyRef.current.push(value);   // B 行：在渲染期間直接改 ref

  return <p>目前共記錄 {historyRef.current.length} 筆</p>;
}

function Tracker({ value }) {
  const prevRef = useRef(value);

  useEffect(() => {
    prevRef.current = value;
  });

  return (
    <p>目前：{value}，上一次：{prevRef.current}</p>
  );
}

