import { renderToStaticMarkup } from 'react-dom/server'
import { forwardRef, useRef } from 'react'
const MyInputOld = forwardRef(function MyInputOld(props, ref) {
  return <input ref={ref} placeholder={props.placeholder} />;
});
function MyInputNew({ placeholder, ref }) {
  return <input ref={ref} placeholder={placeholder} />;
}
function App() {
  const r1 = useRef(null);
  const r2 = useRef(null);
  return (
    <div>
      <MyInputOld placeholder="舊寫法" ref={r1} />
      <MyInputNew placeholder="新寫法" ref={r2} />
    </div>
  );
}
console.log(renderToStaticMarkup(<App />));
